import React, { useState, useEffect } from 'react';
import { useCart } from '../context/CartContext';
import CartToast from '../components/CartToast';
import QuickViewModal from '../components/QuickViewModal';

// Hero
import headphoneHero from '../assets/images/noise cancelling headphone.png';
import watchHero     from '../assets/images/sports water watch.png';
import okodoHero     from '../assets/images/okodo hero black.png';
import sonoImg       from '../assets/images/jamk.png';
import logikeyImg    from '../assets/images/logiket bluetooth keyboard.png';

// Brand logos
import jamxImg    from '../assets/images/jamk.png';
import digitek    from '../assets/images/digitek.png';
import tekReact   from '../assets/images/tek reactjs.png';
import grafbase   from '../assets/images/grafbase.png';
import msiImg     from '../assets/images/msi.png';
import ohbear     from '../assets/images/ohbear.png';
import oak        from '../assets/images/oak.png';
import snyk       from '../assets/images/snyk.png';
import sonex      from '../assets/images/sonex.png';
import stropi     from '../assets/images/stropi.png';

// Top category icons
import laptopImg    from '../assets/images/laptop.png';
import pcGamingImg  from '../assets/images/pc gaming.png';
import gamingImg    from '../assets/images/gaming.png';
import monitorsImg  from '../assets/images/monitors.png';

// Deal of the day product
import xiaomiImg  from '../assets/images/xioma redmi.png';

// Side sale banners
import joystickImg  from '../assets/images/joystick.png';
import ipadImg      from '../assets/images/ipad.png';

// Product grid
import boso2Img   from '../assets/images/boso2 wireless.png';
import ismart     from '../assets/images/ismart 24v.png';
import opodPro    from '../assets/images/opod pro12.png';
import oppoloWatch from '../assets/images/oppolo watch.png';
import ulusk      from '../assets/images/ulusk mini.png';
import msiImg2    from '../assets/images/msi.png';

import './CategoriesPage.css';

const sidebarLinks = [
  'Laptops', 'PC & Computers', 'Cell Phones', 'Tablets',
  'Gaming & VR', 'Networking', 'Cameras', 'Sounds',
  'Office', 'Storage, USB', 'Accessories', 'Clearance',
];

const brands = [
  { img: jamxImg,   name: 'JAMX'     },
  { img: digitek,   name: 'Digitek'  },
  { img: tekReact,  name: 'TekReact' },
  { img: grafbase,  name: 'Grafbase' },
  { img: msiImg,    name: 'MSI'      },
  { img: ohbear,    name: 'OhBear'   },
  { img: oak,       name: 'OAK'      },
  { img: snyk,      name: 'Snyk'     },
  { img: sonex,     name: 'Sonex'    },
  { img: stropi,    name: 'Stropi'   },
];

const topCategories = [
  { img: laptopImg,   name: 'Laptops'    },
  { img: pcGamingImg, name: 'PC Gaming'  },
  { img: gamingImg,   name: 'Headphones' },
  { img: monitorsImg, name: 'Monitors'   },
];

const allProducts = [
  { id: 'e1',  img: laptopImg,   name: 'Laptop Pro 15',         price: '899.00', old: '1099.00', stars: 5 },
  { id: 'e2',  img: ipadImg,     name: 'iPad Pro 12.9"',        price: '799.00', old: '999.00',  stars: 5 },
  { id: 'e3',  img: gamingImg,   name: 'Gaming Headset Pro',    price: '129.00', old: '179.00',  stars: 4 },
  { id: 'e4',  img: monitorsImg, name: '4K Ultra Monitor',      price: '349.00', old: '449.00',  stars: 4 },
  { id: 'e5',  img: joystickImg, name: 'Pro Gaming Controller', price: '69.00',  old: '89.00',   stars: 4 },
  { id: 'e6',  img: msiImg2,     name: 'MSI Gaming Laptop',     price: '1299.00',old: '1599.00', stars: 5 },
  { id: 'e7',  img: boso2Img,    name: 'Boso2 Wireless',        price: '199.00', old: '249.00',  stars: 5 },
  { id: 'e8',  img: ismart,      name: 'iSmart 24V Speaker',    price: '89.00',  old: '119.00',  stars: 3 },
  { id: 'e9',  img: opodPro,     name: 'Opod Pro 12',           price: '599.00', old: '749.00',  stars: 5 },
  { id: 'e10', img: oppoloWatch, name: 'Oppolo Smart Watch',    price: '249.00', old: '349.00',  stars: 4 },
  { id: 'e11', img: ulusk,       name: 'Ulusk Mini Speaker',    price: '59.00',  old: '79.00',   stars: 3 },
  { id: 'e12', img: pcGamingImg, name: 'PC Gaming Tower',       price: '999.00', old: '1299.00', stars: 4 },
];

function Stars({ count }) {
  return (
    <div className="cp-stars">
      {[1,2,3,4,5].map(s => (
        <span key={s} className={s <= count ? 'cp-star filled' : 'cp-star'}>★</span>
      ))}
    </div>
  );
}

function Countdown() {
  const [time, setTime] = useState({ d: 0, h: 9, m: 32, s: 34 });
  useEffect(() => {
    const id = setInterval(() => {
      setTime(t => {
        let { d, h, m, s } = t;
        s--; if (s < 0) { s = 59; m--; }
        if (m < 0) { m = 59; h--; }
        if (h < 0) { h = 23; d--; }
        if (d < 0) d = 0;
        return { d, h, m, s };
      });
    }, 1000);
    return () => clearInterval(id);
  }, []);
  const pad = n => String(Math.max(0, n)).padStart(2, '0');
  return (
    <div className="cp-countdown">
      <p className="cp-hurry">HURRY UP! PROMOTION WILL EXPIRES IN</p>
      <div className="cp-timer">
        {[{ v: time.d, u: 'd' }, { v: time.h, u: 'h' }, { v: time.m, u: 'm' }, { v: time.s, u: 's' }].map(({ v, u }) => (
          <div key={u} className="cp-timer-box">
            <span className="cp-timer-num">{pad(v)}</span>
            <span className="cp-timer-unit">{u}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default function CategoriesPage() {
  const { addToCart, setPage } = useCart();
  const [activeCategory, setActiveCategory] = useState('Laptops');
  const [hovered, setHovered]     = useState(null);
  const [quickView, setQuickView] = useState(null);
  const [toast, setToast]         = useState(null);
  const [dealQty, setDealQty]     = useState(1);

  function handleAdd(p) {
    addToCart({ ...p, desc: 'Premium electronics product.' });
    setToast(p);
  }

  return (
    <div className="cp-page">
      <div className="cp-layout">

        {/* ══ LEFT SIDEBAR ══ */}
        <aside className="cp-sidebar">
          <p className="cp-sale-tag">SALE 40% OFF</p>
          <ul className="cp-sidebar-list">
            {sidebarLinks.map(link => (
              <li
                key={link}
                className={`cp-sidebar-item ${activeCategory === link ? 'active' : ''}`}
                onClick={() => setActiveCategory(link)}
              >
                {link}
              </li>
            ))}
          </ul>
        </aside>

        {/* ══ MAIN CONTENT ══ */}
        <div className="cp-main">

          {/* ── Hero + right cards ── */}
          <div className="cp-top-row">
            <div className="cp-hero">
              <img src={headphoneHero} alt="Headphone" className="cp-hero-img" />
            </div>
            <div className="cp-right-cards">
              <div className="cp-right-card">
                <div className="cp-right-card-text">
                  <p className="cp-right-brand">XOMIA</p>
                  <p className="cp-right-title">Sport Water Resistance Watch</p>
                  <button className="cp-right-btn">SHOP NOW</button>
                </div>
                <img src={watchHero} alt="Watch" className="cp-right-img" />
              </div>
              <div className="cp-right-card cp-right-card-dark">
                <div className="cp-right-card-text">
                  <p className="cp-right-brand">OKODO</p>
                  <p className="cp-right-title">HERO 11+ BLACK</p>
                  <p className="cp-right-from">FROM</p>
                  <p className="cp-right-price">$169</p>
                </div>
                <img src={okodoHero} alt="Camera" className="cp-right-img" />
              </div>
            </div>
          </div>

          {/* ── Small cards ── */}
          <div className="cp-small-row">
            <div className="cp-small-card">
              <img src={sonoImg} alt="Sono Playgo 5" className="cp-small-img" />
              <div className="cp-small-info">
                <p className="cp-small-name">Sono Playgo 5</p>
                <p className="cp-small-price">from <strong>$569</strong></p>
                <a href="#!" className="cp-small-link">DISCOVER NOW</a>
              </div>
            </div>
            <div className="cp-small-card cp-small-card-alt">
              <div className="cp-small-info">
                <p className="cp-small-name">Logitek Bluetooth</p>
                <a href="#!" className="cp-small-name-link">Keyboard</a>
                <p className="cp-small-sub">Best for all device</p>
              </div>
              <img src={logikeyImg} alt="Keyboard" className="cp-small-img" />
            </div>
          </div>

          {/* ── Featured Brands + Top Categories ── */}
          <div className="cp-brands-cats-row">
            <div className="cp-brands-section">
              <div className="cp-section-header">
                <h3 className="cp-section-title">FEATURED BRANDS</h3>
                <a href="#!" className="cp-view-all">View All</a>
              </div>
              <div className="cp-brands-grid">
                {brands.map(b => (
                  <div key={b.name} className="cp-brand-item">
                    <img src={b.img} alt={b.name} className="cp-brand-img" />
                  </div>
                ))}
              </div>
            </div>

            <div className="cp-topcats-section">
              <div className="cp-section-header">
                <h3 className="cp-section-title">TOP CATEGORIES</h3>
                <a href="#!" className="cp-view-all">View All</a>
              </div>
              <div className="cp-topcats-grid">
                {topCategories.map(c => (
                  <div key={c.name} className="cp-topcat-item">
                    <img src={c.img} alt={c.name} className="cp-topcat-img" />
                    <p className="cp-topcat-name">{c.name}</p>
                  </div>
                ))}
              </div>
            </div>
          </div>

          {/* ── Deals of the Day + Side banners ── */}
          <div className="cp-deals-row">
            {/* Deal of the day */}
            <div className="cp-deal-section">
              <div className="cp-deal-header">
                <h3 className="cp-deal-title">DEALS OF THE DAY</h3>
              </div>
              <div className="cp-deal-body">
                {/* Thumbnails */}
                <div className="cp-deal-thumbs">
                  {[xiaomiImg, xiaomiImg, xiaomiImg].map((img, i) => (
                    <img key={i} src={img} alt="thumb" className="cp-deal-thumb" />
                  ))}
                </div>
                {/* Main image */}
                <div className="cp-deal-main-img">
                  <span className="cp-deal-save">SAVE<br />$199.00</span>
                  <img src={xiaomiImg} alt="Xioma Redmi" className="cp-deal-img" />
                </div>
                {/* Product info */}
                <div className="cp-deal-info">
                  <p className="cp-deal-reviews">(12)</p>
                  <h3 className="cp-deal-name">Xioma Redmi Note 11 Pro 256GB 2023, Black Smartphone</h3>
                  <div className="cp-deal-price-row">
                    <span className="cp-deal-price">$569.00</span>
                    <span className="cp-deal-old">$759.00</span>
                  </div>
                  <ul className="cp-deal-specs">
                    <li>Intel LGA 1700 Socket: Supports 13th & 12th Gen Intel Core</li>
                    <li>DDR5 Compatible: 4*SMD DIMMs with XMP 3.0 Memory</li>
                    <li>Commanding Power Design: Twin 16+1+2 Phases Digital VRM</li>
                  </ul>
                  <div className="cp-deal-tags">
                    <span className="cp-deal-tag-free">FREE SHIPPING</span>
                    <span className="cp-deal-tag-gift">FREE GIFT</span>
                  </div>
                  <Countdown />
                  <div className="cp-deal-progress-wrap">
                    <div className="cp-deal-progress-bar">
                      <div className="cp-deal-progress-fill" style={{ width: '35%' }} />
                    </div>
                    <p className="cp-deal-sold">Sold: <strong>26/75</strong></p>
                  </div>
                </div>
              </div>
            </div>

            {/* Side sale banners */}
            <div className="cp-side-banners">
              <div className="cp-side-banner cp-side-banner-dark">
                <div className="cp-side-banner-text">
                  <p className="cp-side-sale">SALE</p>
                  <p className="cp-side-pct">50%</p>
                </div>
                <img src={joystickImg} alt="Gaming" className="cp-side-banner-img" />
              </div>
              <div className="cp-side-banner cp-side-banner-green">
                <img src={ipadImg} alt="iPad" className="cp-side-banner-img" />
              </div>
            </div>
          </div>

          {/* ── Product Grid ── */}
          <div className="cp-grid">
            {allProducts.map(p => (
              <div
                key={p.id}
                className="cp-card"
                onMouseEnter={() => setHovered(p.id)}
                onMouseLeave={() => setHovered(null)}
              >
                <div
                  className="cp-img-wrap"
                  onClick={() => setQuickView(p)}
                  style={{ cursor: 'pointer' }}
                >
                  <img src={p.img} alt={p.name} className="cp-img" />
                  {hovered === p.id && (
                    <div className="cp-hover-overlay">
                      <button
                        className="cp-quick-view-btn"
                        onClick={e => { e.stopPropagation(); setQuickView(p); }}
                      >
                        Quick View
                      </button>
                    </div>
                  )}
                </div>
                <div className="cp-info">
                  <p className="cp-name">{p.name}</p>
                  <Stars count={p.stars} />
                  <div className="cp-price-row">
                    <span className="cp-price">${p.price}</span>
                    <span className="cp-old">${p.old}</span>
                  </div>
                  {hovered === p.id && (
                    <button className="cp-add-btn" onClick={() => handleAdd(p)}>
                      ADD TO CART
                    </button>
                  )}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {quickView && (
        <QuickViewModal
          product={{ ...quickView, cat: 'Electronics', desc: 'Premium electronics product.' }}
          onClose={() => setQuickView(null)}
          onAddedToCart={p => setToast(p)}
        />
      )}
      {toast && (
        <CartToast
          product={toast}
          onClose={() => setToast(null)}
          onViewCart={() => { setToast(null); setPage('cart'); }}
        />
      )}
    </div>
  );
}
